package co.edu.elecciones.controller; import co.edu.elecciones.commons.dto.ApiResponse; import co.edu.elecciones.domain.*; import co.edu.elecciones.dto.Requests.CandidateRequest; import co.edu.elecciones.repository.*; import co.edu.elecciones.service.AuditService; import jakarta.servlet.http.HttpServletRequest; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/candidatos") public class CandidatosController { private final CandidateRepository repo; private final PartyRepository parties; private final AuditService audit; public CandidatosController(CandidateRepository r,PartyRepository p,AuditService a){repo=r;parties=p;audit=a;} @GetMapping public ApiResponse<List<Candidate>> all(){return ApiResponse.ok("OK",repo.findAll());} @GetMapping("/{id}") public ApiResponse<Candidate> one(@PathVariable Long id){return ApiResponse.ok("OK",repo.findById(id).orElseThrow());} @PostMapping public ApiResponse<Candidate> create(@RequestBody CandidateRequest req,HttpServletRequest http){Candidate c=new Candidate(); map(c,req); var s=repo.save(c); audit.log("CREATE","Candidate",s.id,"Creación",http); return ApiResponse.ok("Creado",s);} @PutMapping("/{id}") public ApiResponse<Candidate> update(@PathVariable Long id,@RequestBody CandidateRequest req,HttpServletRequest http){var c=repo.findById(id).orElseThrow(); map(c,req); var s=repo.save(c); audit.log("UPDATE","Candidate",s.id,"Actualización",http); return ApiResponse.ok("Actualizado",s);} @DeleteMapping("/{id}") public ApiResponse<Void> delete(@PathVariable Long id,HttpServletRequest http){repo.deleteById(id); audit.log("DELETE","Candidate",id,"Eliminación",http); return ApiResponse.ok("Eliminado",null);} private void map(Candidate c,CandidateRequest r){ c.name=r.name(); c.vicePresidentName=r.vicePresidentName(); c.party=parties.findById(r.partyId()).orElseThrow(); c.electionType=r.electionType(); c.department=r.department(); c.municipality=r.municipality(); if(r.active()!=null)c.active=r.active(); }}
